import { Transaction, FileModel } from '../../types';
import { DateResolver } from '../processors/DateResolver';
import { AmountResolver } from '../processors/AmountResolver';
import { extractTransactionsFromComplexBlock } from '../../services/geminiService';

/**
 * 📜 CONTRACT EXECUTOR (V7 - BLINDAGEM FINAL)
 * Este motor é o funil absoluto para modelos treinados.
 * Garante que se houver um modelo aplicado, ele seja a verdade única até a UI.
 */
export const ContractExecutor = {
    async apply(model: FileModel, normalizedContent: string): Promise<Transaction[]> {
        // 1. DEFINIÇÃO DA FONTE (INPUT BLINDADO)
        // Se o modelo tem um snippet treinado, ele é MANDATÓRIO para garantir paridade com o treino.
        // Caso contrário, usa o conteúdo normalizado entregue pelo Orchestrator.
        const sourceContent = model.snippet || normalizedContent || "";
        const lines = sourceContent.split(/\r?\n/).filter(l => l.trim().length > 0);

        console.log(`[Executor:INPUT] Model: ${model.name} | Source: ${model.snippet ? 'SNIPPET' : 'CONTENT'} | Lines: ${lines.length}`);

        const extractionMode = model.mapping.extractionMode || 'COLUMNS';
        let results: Transaction[] = [];

        try {
            // 2. PROCESSAMENTO ISOLADO POR MODO
            if (extractionMode === 'BLOCK') {
                const aiResults = await extractTransactionsFromComplexBlock(sourceContent);
                results = (aiResults || []).map((tx: any, idx: number) => ({
                    id: `contract-block-${model.id}-${idx}-${Date.now()}`,
                    date: tx.date,
                    description: tx.description,
                    rawDescription: tx.description,
                    amount: tx.amount,
                    originalAmount: String(tx.amount),
                    cleanedDescription: tx.description,
                    contributionType: tx.type || 'AUTO',
                    paymentMethod: tx.paymentMethod || 'OUTROS'
                }));
            } else {
                // MODO COLUNAS (MAPEAMENTO 1:1 BASEADO NO CONTRATO DO MODELO)
                const { 
                    dateColumnIndex, 
                    descriptionColumnIndex, 
                    amountColumnIndex, 
                    paymentMethodColumnIndex, 
                    typeColumnIndex,
                    skipRowsStart 
                } = model.mapping;

                const delimiter = model.fingerprint.delimiter || ';';
                const yearAnchor = DateResolver.discoverAnchorYear(sourceContent);

                results = lines.reduce((acc: Transaction[], line, index) => {
                    // Pula linhas iniciais conforme definido no modelo (Headers/Lixo)
                    if (index < (skipRowsStart || 0)) return acc;

                    const cols = line.split(delimiter);

                    // Extração Bruta baseada nos índices salvos
                    const rawDate = (cols[dateColumnIndex] !== undefined) ? (cols[dateColumnIndex] || '').trim() : '';
                    const rawDesc = (cols[descriptionColumnIndex] !== undefined) ? (cols[descriptionColumnIndex] || '').trim() : '';
                    const rawAmount = (cols[amountColumnIndex] !== undefined) ? (cols[amountColumnIndex] || '').trim() : '';

                    // Validação mínima: Se não tem os dados básicos, ignora a linha silenciosamente
                    if (!rawDate && !rawDesc && !rawAmount) return acc;

                    // Normalização técnica (Sinal, Decimal e Data ISO)
                    const stdAmount = AmountResolver.clean(rawAmount);
                    const numericValue = parseFloat(stdAmount);
                    const isoDate = DateResolver.resolveToISO(rawDate, yearAnchor);

                    // Resolução de Meta-colunas (Tipo e Forma)
                    const finalType = (typeColumnIndex !== undefined && typeColumnIndex !== -1)
                        ? (cols[typeColumnIndex] || 'AUTO').trim().toUpperCase()
                        : 'AUTO';

                    const finalForm = (paymentMethodColumnIndex !== undefined && paymentMethodColumnIndex !== -1)
                        ? (cols[paymentMethodColumnIndex] || 'OUTROS').trim().toUpperCase()
                        : 'OUTROS';

                    acc.push({
                        id: `contract-col-${model.id}-${index}-${Date.now()}`,
                        date: isoDate || rawDate,
                        description: rawDesc,
                        rawDescription: rawDesc,
                        amount: isNaN(numericValue) ? 0 : numericValue,
                        originalAmount: rawAmount,
                        cleanedDescription: rawDesc, 
                        contributionType: finalType,
                        paymentMethod: finalForm
                    });

                    return acc;
                }, []);
            }

            // 3. RETORNO ÚNICO E DETERMINÍSTICO (OUTPUT BLINDADO)
            // O retorno é imutável e segue estritamente o que o modelo extraiu.
            console.log(`[Executor:OUTPUT] Final Count: ${results.length}`);
            return results;

        } catch (error) {
            console.error(`[Executor:CRITICAL_FAILURE] Model: ${model.name}`, error);
            // Em caso de erro crítico no motor do modelo, retorna lista vazia para impedir poluição.
            return [];
        }
    }
};

import { supabase } from './supabaseClient';
import { FileModel } from '../types';
import { Logger } from './monitoringService';
import { get, set } from 'idb-keyval';

const PERSISTENT_STORAGE_KEY = 'identificapix-models-storage-v11';

const getConsolidatedLocalModels = async (): Promise<FileModel[]> => {
    try {
        const currentModels = await get(PERSISTENT_STORAGE_KEY);
        return Array.isArray(currentModels) ? currentModels : [];
    } catch (e) { 
        return []; 
    }
};

const mapDbRowToModel = (row: any): FileModel => {
    const parseJson = (val: any) => {
        if (typeof val === 'string') {
            try { return JSON.parse(val); } catch (e) { return val; }
        }
        return val;
    };

    const model = {
        id: row.id,
        name: row.name,
        user_id: row.user_id,
        version: row.version || 1,
        lineage_id: row.lineage_id || row.id,
        is_active: row.is_active,
        status: row.status || 'draft',
        fingerprint: parseJson(row.fingerprint),
        mapping: parseJson(row.mapping),
        parsingRules: row.parsing_rules ? parseJson(row.parsing_rules) : { ignoredKeywords: [], rowFilters: [] },
        snippet: row.snippet,
        createdAt: row.created_at || new Date().toISOString(),
        lastUsedAt: row.last_used_at
    };

    return model;
};

export const modelService = {
    /**
     * SALVAMENTO BLINDADO COM AUTH
     * Garante que o modelo só seja persistido se houver sessão ativa e user_id válido.
     */
    saveModel: async (model: Omit<FileModel, 'id' | 'createdAt'>): Promise<FileModel | null> => {
        try {
            // 1. Validação de Sessão e Autorização
            const { data: { session } } = await supabase.auth.getSession();

            if (!session || !session.user || !model.user_id) {
                Logger.error("Falha de Segurança: Tentativa de salvar modelo sem sessão ativa ou user_id.");
                throw new Error("Sessão expirada ou usuário não identificado. Por favor, faça login novamente.");
            }

            if (model.user_id !== session.user.id) {
                Logger.error("Falha de Integridade: user_id do modelo diverge da sessão ativa.");
                throw new Error("Erro de permissão: Os dados pertencem a outra conta.");
            }

            // 2. Preparação de Linhagem (Desativação atômica via Auth Header)
            if (model.lineage_id) {
                await supabase.from('file_models')
                    .update({ is_active: false })
                    .eq('lineage_id', model.lineage_id)
                    .eq('user_id', session.user.id); // Garantia extra de escopo
            }

            // 3. Payload de Persistência
            const dbPayload = {
                name: model.name,
                user_id: session.user.id, // Usa ID da sessão por segurança
                version: model.version || 1,
                lineage_id: model.lineage_id,
                is_active: true,
                status: model.status || 'approved',
                fingerprint: model.fingerprint,
                mapping: model.mapping,
                parsing_rules: model.parsingRules || { ignoredKeywords: [], rowFilters: [] },
                snippet: model.snippet || null
            };

            // 4. Inserção com validação de retorno
            const { data, error, status } = await supabase
                .from('file_models')
                .insert([dbPayload])
                .select()
                .single();

            if (error || status !== 201) {
                Logger.error(`Erro Supabase (Status: ${status}):`, error);
                throw new Error(error?.message || `Falha na gravação remota (Status: ${status})`);
            }

            const savedModel = mapDbRowToModel(data);

            // 5. Sincronização Local (Offline First)
            const currentLocals = await getConsolidatedLocalModels();
            const updatedLocals = [savedModel, ...currentLocals.filter(m => m.lineage_id !== model.lineage_id)];
            await set(PERSISTENT_STORAGE_KEY, updatedLocals);

            console.log(`[ModelService:SUCCESS] Modelo persistido com token válido. ID: ${savedModel.id}`);
            return savedModel;

        } catch (error: any) {
            Logger.error("Erro crítico ao persistir modelo", error);
            throw error; // Repropaga para a UI exibir o brinde de erro real
        }
    },

    getUserModels: async (userId: string): Promise<FileModel[]> => {
        let remoteModels: FileModel[] = [];
        try {
            const { data, error } = await supabase
                .from('file_models')
                .select('*')
                .eq('is_active', true);

            if (data) {
                remoteModels = data.map(mapDbRowToModel);
            }
        } catch (e) {
            console.error("Falha ao ler modelos remotos", e);
        }

        const localModels = await getConsolidatedLocalModels();
        const uniqueModels = new Map<string, FileModel>();

        [...remoteModels, ...localModels].forEach(m => {
            const existing = uniqueModels.get(m.lineage_id);
            if (!existing || new Date(m.createdAt) > new Date(existing.createdAt)) {
                uniqueModels.set(m.lineage_id, m);
            }
        });

        return Array.from(uniqueModels.values());
    },

    deleteModel: async (id: string) => {
        const { data: { session } } = await supabase.auth.getSession();
        if (!session) return false;

        const { error } = await supabase
            .from('file_models')
            .delete()
            .eq('id', id)
            .eq('user_id', session.user.id);

        return !error;
    },

    getAllModelsAdmin: async (): Promise<FileModel[]> => {
        const { data, error } = await supabase
            .from('file_models')
            .select('*')
            .order('created_at', { ascending: false });

        if (error) return [];
        return data.map(mapDbRowToModel);
    },

    updateModelName: async (id: string, name: string) => {
        const { data: { session } } = await supabase.auth.getSession();
        if (!session) return false;

        const { error } = await supabase
            .from('file_models')
            .update({ name })
            .eq('id', id)
            .eq('user_id', session.user.id);

        return !error;
    }
};

