const getAIClient = () => {
    const apiKey = process.env.API_KEY;
    if (!apiKey) {
        console.error("CRITICAL: Gemini API Key is missing.");
        throw new Error("Chave de API do Gemini não configurada no ambiente.");
    }
    return new GoogleGenAI({ apiKey });
};

/**
 * 🛡️ JSON SHIELD: Sanitiza e repara strings JSON potencialmente truncadas ou malformadas pela IA.
 */
const safeJsonParse = (text: string, fallback: any = []) => {
    let sanitized = text.trim();

    // Remove possíveis prefixos de markdown
    if (sanitized.startsWith('```json')) sanitized = sanitized.replace(/^```json/, '');
    if (sanitized.endsWith('```')) sanitized = sanitized.replace(/```$/, '');
    sanitized = sanitized.trim();

    try {
        return JSON.parse(sanitized);
    } catch (e) {
        console.warn("[IA:JSON_REPAIR] Tentando reparar JSON quebrado...");
        // Reparo básico de aspas e colchetes truncados
        if (sanitized.startsWith('[') && !sanitized.endsWith(']')) sanitized += ']';
        if (sanitized.startsWith('{') && !sanitized.endsWith('}')) sanitized += '}';

        try {
            return JSON.parse(sanitized);
        } catch (innerError) {
            Logger.error("Falha Crítica no Parser de IA. Conteúdo bruto:", { text: sanitized.substring(0, 500) });
            return fallback;
        }
    }
};

async function callWithSimpleRetry(fn: () => Promise<any>, retries = 3, delay = 4000): Promise<any> {
    try {
        return await fn();
    } catch (error: any) {
        const msg = error?.message?.toLowerCase() || "";
        if (msg.includes("requested entity was not found")) {
             if (retries <= 0) throw error;
             if (typeof window !== 'undefined' && (window as any).aistudio) {
                 try {
                     await (window as any).aistudio.openSelectKey();
                     return callWithSimpleRetry(fn, retries - 1, delay); 
                 } catch (e) { throw error; }
             }
        }
        if (retries > 0) {
            await new Promise(r => setTimeout(r, delay));
            return callWithSimpleRetry(fn, retries - 1, delay);
        }
        throw error;
    }
};

/**
 * MOTOR DE EXTRAÇÃO DE BLOCO (V4 - ULTRA CONTEXTUAL)
 */
export const extractTransactionsFromComplexBlock = async (rawText: string): Promise<any[]> => {
    console.log("[IA:EXECUTE] Iniciando extração contextual por bloco...");
    return await callWithSimpleRetry(async () => {
        const ai = getAIClient();
        const prompt = `VOCÊ É UM ANALISTA BANCÁRIO DE ALTA FIDELIDADE. 
        Sua missão é ler o texto abaixo e extrair TODAS as transações financeiras.

        CONTEÚDO DO DOCUMENTO:
        ${rawText.substring(0, 12000)}

        REGRAS DE OURO:
        1. Ignore linhas de saldo (Saldo anterior, saldo bloqueado, etc).
        2. Capture o NOME completo do favorecido/pagador.
        3. Determine o valor numérico exato. 
        4. No campo "paymentMethod", identifique se é PIX, TED, DOC ou DINHEIRO.
        5. Se o valor for uma entrada (Crédito/C), ele é POSITIVO.
        6. Se o valor for uma saída (Débito/D/-), ele é NEGATIVO.
        7. A data deve ser ISO (YYYY-MM-DD). Use o ano 2025 se não estiver explícito.

        RETORNE EXCLUSIVAMENTE UM ARRAY JSON:
        [{ 
          "date": "YYYY-MM-DD", 
          "description": "NOME_DO_FAVORECIDO", 
          "amount": 123.45, 
          "paymentMethod": "PIX",
          "type": "CATEGORIA"
        }]`;

        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: prompt,
            config: {
                temperature: 0,
                responseMimeType: "application/json"
            }
        });

        const results = safeJsonParse(response.text || "[]");
        console.log(`[IA:DONE] Extração concluída. Itens encontrados: ${results.length}`);
        return results;
    });
};

/**
 * Extrai dados estruturados baseado em um exemplo de correção do usuário.
 */
export const extractStructuredDataByExample = async (rawText: string, instruction: string): Promise<any> => {
    console.log("[IA:LEARN] Aprendendo novo padrão estrutural por exemplo...");
    return await callWithSimpleRetry(async () => {
        const ai = getAIClient();
        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: `${instruction}\n\nTEXTO:\n${rawText}`,
            config: {
                temperature: 0,
                responseMimeType: "application/json",
                responseSchema: {
                    type: Type.OBJECT,
                    properties: {
                        rows: {
                            type: Type.ARRAY,
                            items: {
                                type: Type.OBJECT,
                                properties: {
                                    date: { type: Type.STRING },
                                    description: { type: Type.STRING },
                                    paymentMethod: { type: Type.STRING },
                                    amount: { type: Type.NUMBER },
                                    type: { type: Type.STRING }
                                }
                            }
                        }
                    }
                }
            }
        });
        const result = safeJsonParse(response.text || "{}", { rows: [] });
        console.log(`[IA:LEARN_DONE] Padrão aprendido. Linhas processadas: ${result?.rows?.length || 0}`);
        return result;
    });
};

