export const inferMappingFromSample = async (sampleText: string): Promise<any> => {
    console.log("[IA:PROBE] Inferindo mapeamento inicial...");
    return await callWithSimpleRetry(async () => {
        const ai = getAIClient();
        const prompt = `Analise o layout deste extrato financeiro.
        DADOS:
        ${sampleText.substring(0, 6000)}

        RETORNE JSON:
        {
          "extractionMode": "COLUMNS" | "BLOCK",
          "dateColumnIndex": number,
          "descriptionColumnIndex": number,
          "amountColumnIndex": number,
          "paymentMethodColumnIndex": number | null,
          "typeColumnIndex": number | null,
          "skipRowsStart": number
        }`;

        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: prompt,
            config: { temperature: 0, responseMimeType: "application/json" }
        });

        const mapping = safeJsonParse(response.text || "null", null);
        if (mapping) console.log("[IA:PROBE_DONE] Mapeamento sugerido com sucesso.");
        return mapping;
    });
};

export const getAISuggestion = async (transaction: Transaction, contributors: Contributor[]): Promise<string> => {
    return await callWithSimpleRetry(async () => {
        const ai = getAIClient();
        const prompt = `Analise: "${transaction.description}". Qual contribuinte melhor se encaixa? Lista: [${contributors.map(c => c.name).join(', ')}]. Responda apenas o nome.`;
        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: prompt,
            config: { temperature: 0.1 }
        });
        return response.text ? response.text.trim() : "Nenhuma sugestão clara";
    });
};

