            // MODO: EXTRAÇÃO DE BLOCO (Contextual IA)
            if (mapping.extractionMode === 'BLOCK') {
                const textForAi = gridData.slice(0, 1000).map(row => row.join(' ')).join('\n');
                const aiResult = await extractTransactionsFromComplexBlock(textForAi);

                if (aiResult && aiResult.length > 0) {
                    setProcessedTransactions(aiResult.map((tx, i) => ({
                        ...tx,
                        id: `block-sim-${i}-${Date.now()}`,
                        rawDescription: tx.description,
                        cleanedDescription: tx.description,
                        originalAmount: String(tx.amount),
                        contributionType: tx.type || '',
                        paymentMethod: tx.paymentMethod || '',
                        isValid: true,
                        status: 'valid'
                    })));
                } else {
                    setProcessedTransactions([]);
                }
                return;
            }

            // MODO TRADICIONAL: COLUNAS FIXAS
            const { dateColumnIndex, descriptionColumnIndex, amountColumnIndex, paymentMethodColumnIndex, skipRowsStart } = mapping;
            const newTransactions: SafeTransaction[] = [];
            const yearAnchor = DateResolver.discoverAnchorYear(gridData);

            gridData.forEach((cols, index) => {
                if (!RowValidator.isPotentialRow(cols)) return;
                const isSkipped = index < (skipRowsStart || 0);

                if (dateColumnIndex === -1 && descriptionColumnIndex === -1 && amountColumnIndex === -1) {
                    newTransactions.push({ 
                        id: `sim-raw-${index}`, 
                        date: "---", 
                        description: cols.join(' | ').substring(0, 80), 
                        rawDescription: cols.join('|'), 
                        amount: 0, 
                        originalAmount: "0.00", 
                        cleanedDescription: cols.join(' | '), 
                        contributionType: "", 
                        paymentMethod: "", 
                        sourceIndex: index, 
                        isValid: false, 
                        status: 'pending' 
                    });
                    return;
                }

                const rawDate = (cols[dateColumnIndex] || '').trim();
                const rawDesc = (cols[descriptionColumnIndex] || '').trim();
                const rawAmount = (cols[amountColumnIndex] || '').trim();

                const rawForm = (paymentMethodColumnIndex !== undefined && cols[paymentMethodColumnIndex])
                    ? cols[paymentMethodColumnIndex].trim().toUpperCase()
                    : TypeResolver.resolveFromDescription(rawDesc);

                const isoDate = DateResolver.resolveToISO(rawDate, yearAnchor);
                const amountStr = AmountResolver.clean(rawAmount);
                const amount = parseFloat(amountStr);
                const isValid = RowValidator.isValid(isoDate, rawDesc, amountStr) && !isSkipped;

                newTransactions.push({ 
                    id: `sim-${index}-${Date.now()}`,
                    date: isoDate || rawDate || "---", 
                    description: rawDesc || "---", 
                    rawDescription: rawDesc || "---", 
                    paymentMethod: rawForm || "",
                    amount: isNaN(amount) ? 0 : amount, 
                    originalAmount: rawAmount, 
                    cleanedDescription: rawDesc,
                    contributionType: 'AUTO', 
                    sourceIndex: index, 
                    isValid, 
                    status: isSkipped ? 'ignored' : (isValid ? 'valid' : 'error') 
                });
            });
            setProcessedTransactions(newTransactions);
        } catch (e) {
            console.error("Simulation error:", e);
        } finally {
            setIsSimulating(false);
        }
    }, [gridData, activeMapping]);

    useEffect(() => {
        const dataHash = gridData.length > 0 ? `${gridData.length}-${gridData[0].join('|').substring(0, 50)}` : 'empty';
        const mappingKey = JSON.stringify(activeMapping);
        if (dataHash !== lastDataRef.current || mappingKey !== lastMappingRef.current) {
            lastDataRef.current = dataHash;
            lastMappingRef.current = mappingKey;
            runSimulation();
        }
    }, [gridData, activeMapping, runSimulation]);

    return {
        processedTransactions,
        isSimulating,
        runSimulation,
        editingRowIndex,
        editingRowData,
        setEditingRowData,
        startEdit: (tx: any, idx: number) => { 
            setEditingRowIndex(idx); 
            // 🛡️ Blindagem: Garante que strings opcionais nunca sejam undefined no estado de edição
            setEditingRowData({ 
                ...tx,
                contributionType: tx.contributionType || '',
                paymentMethod: tx.paymentMethod || ''
            }); 
        },
        saveRow: (onLearned?: any) => {
            if (editingRowIndex !== null && editingRowData) {
                const updatedTx = { ...editingRowData, status: 'edited' as const, isValid: true };
                setProcessedTransactions(prev => { const n = [...prev]; n[editingRowIndex] = updatedTx; return n; });
                if (onLearned && editingRowData.sourceIndex !== undefined) onLearned(gridData[editingRowData.sourceIndex], updatedTx);
                setEditingRowIndex(null);
            }
        },
        cancelEdit: () => setEditingRowIndex(null)
    };
};

import React from 'react';
import { PencilIcon, CheckCircleIcon, XMarkIcon, DocumentArrowDownIcon, SparklesIcon } from '../../Icons';

interface SimulatedResultsTableProps {
    transactions: any[];
    activeMapping: boolean;
    isTestMode: boolean;
    editingRowIndex: number | null;
    editingRowData: any | null;
    onStartEdit: (tx: any, idx: number) => void;
    onSaveRow: () => void;
    onCancelEdit: () => void;
    onUpdateEditingData: (data: any) => void;
}

const formatToBRL = (val: string | number) => {
    const num = typeof val === 'string' ? parseFloat(val) : val;
    if (isNaN(num)) return 'R$ 0,00';
    return num.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' });
};

export const SimulatedResultsTable: React.FC<SimulatedResultsTableProps> = ({
    transactions,
    activeMapping,
    isTestMode,
    editingRowIndex,
    editingRowData,
    onStartEdit,
    onSaveRow,
    onCancelEdit,
    onUpdateEditingData
}) => {
    if (transactions.length === 0) {
        return (
            <div className="flex flex-col items-center justify-center h-full text-slate-400 p-8 text-center bg-white dark:bg-[#0F172A]">
                <div className="relative mb-4">
                    <div className="absolute inset-0 bg-brand-blue blur-xl opacity-20 animate-pulse rounded-full"></div>
                    <SparklesIcon className="w-12 h-12 text-brand-blue relative z-10 animate-bounce" />
                </div>
                <h5 className="text-sm font-bold text-slate-800 dark:text-white uppercase tracking-widest mb-2">IA em Ação</h5>
                <p className="text-xs text-slate-500 dark:text-slate-400 max-w-xs mx-auto leading-relaxed">
                    A inteligência artificial está transformando o visual em dados estruturados. Aguarde alguns segundos...
                </p>
            </div>
        );
    }

    return (
        <table className="w-full text-xs text-left border-collapse">
            <thead className="sticky top-0 bg-white dark:bg-slate-900 z-10 border-b border-slate-200 dark:border-slate-700 shadow-sm">
                <tr>
                    <th className="p-3 font-bold text-slate-500 dark:text-slate-400 w-24">Data</th>
                    <th className="p-3 font-bold text-slate-500 dark:text-slate-400">Descrição (Limpa)</th>
                    <th className="p-3 font-bold text-slate-500 dark:text-slate-400 w-24">Tipo</th>
                    <th className="p-3 font-bold text-slate-500 dark:text-slate-400 w-24">Forma</th>
                    <th className="p-3 font-bold text-slate-500 dark:text-slate-400 text-right w-28">Valor</th>
                    <th className="p-3 font-bold text-slate-500 dark:text-slate-400 text-center w-16">Ação</th>
                </tr>
            </thead>
            <tbody className="divide-y divide-slate-100 dark:divide-slate-800/50">
                {transactions.map((tx, idx) => {
                    const isEditing = editingRowIndex === idx;
                    const isPending = tx.status === 'pending';
                    const isInvalid = !tx.isValid && tx.status === 'error'; 
                    const isIgnored = tx.status === 'ignored';

                    if (isEditing && editingRowData) {
                        return (
                            <tr key={tx.id} className="bg-blue-50 dark:bg-blue-900/20">
                                <td className="p-2">
                                    <input type="text" value={editingRowData.date || ''} onChange={(e) => onUpdateEditingData({...editingRowData, date: e.target.value})} className="w-full bg-white dark:bg-slate-800 border border-blue-300 rounded px-1 text-xs" />
                                </td>
                                <td className="p-2">
                                    <input type="text" value={editingRowData.cleanedDescription || ''} onChange={(e) => onUpdateEditingData({...editingRowData, cleanedDescription: e.target.value})} className="w-full bg-white dark:bg-slate-800 border border-blue-300 rounded px-1 text-xs" />
                                </td>
                                <td className="p-2">
                                    <input type="text" value={editingRowData.contributionType || ''} onChange={(e) => onUpdateEditingData({...editingRowData, contributionType: e.target.value})} className="w-full bg-white dark:bg-slate-800 border border-blue-300 rounded px-1 text-xs" />
                                </td>
                                <td className="p-2">
                                    <input type="text" value={editingRowData.paymentMethod || ''} onChange={(e) => onUpdateEditingData({...editingRowData, paymentMethod: e.target.value})} className="w-full bg-white dark:bg-slate-800 border border-blue-300 rounded px-1 text-xs" />
                                </td>
                                <td className="p-2">
                                    <input 
                                        type="number" 
                                        step="0.01"
                                        value={editingRowData.amount} 
                                        onChange={(e) => onUpdateEditingData({...editingRowData, amount: parseFloat(e.target.value) || 0})} 
                                        className="w-full bg-white dark:bg-slate-800 border border-blue-300 rounded px-1 text-xs text-right" 
                                    />
                                </td>
                                <td className="p-2 text-center">
                                    <div className="flex items-center justify-center gap-1">
                                        <button onClick={onSaveRow} className="p-1 text-emerald-600 hover:bg-emerald-100 rounded transition-colors"><CheckCircleIcon className="w-4 h-4" /></button>
                                        <button onClick={onCancelEdit} className="p-1 text-red-500 hover:bg-red-100 rounded transition-colors"><XMarkIcon className="w-4 h-4" /></button>
                                    </div>
                                </td>
                            </tr>
                        );
                    }

                    return (
                        <tr key={tx.id} className={`hover:bg-slate-50 dark:hover:bg-slate-800/50 transition-colors group ${isIgnored ? 'opacity-30 bg-slate-100 dark:bg-slate-900 pointer-events-none grayscale' : isInvalid ? 'opacity-60 bg-red-50/20' : isPending ? 'bg-amber-50 dark:bg-amber-900/20' : ''}`}>
                            <td className="p-3 font-mono text-slate-600 dark:text-slate-300 truncate max-w-[100px]" title={tx.date}>
                                {activeMapping && tx.isValid && tx.date && tx.date.includes('-') ? tx.date.split('-').reverse().join('/') : (tx.date || '---')}
                            </td>
                            <td className="p-3">
                                <div className={`font-bold truncate max-w-[300px] ${isInvalid ? 'text-red-500' : 'text-slate-800 dark:text-slate-200'} ${isIgnored ? 'line-through' : ''}`} title={tx.cleanedDescription}>
                                    {tx.cleanedDescription}
                                </div>
                                {isIgnored && <span className="text-[8px] uppercase font-bold text-slate-400">Ignorado</span>}
                                {isPending && <span className="text-[8px] uppercase font-bold text-amber-500">Pendente</span>}
                            </td>
                            <td className="p-3 text-slate-500 uppercase text-[10px]">{tx.contributionType || 'OUTROS'}</td>
                            <td className="p-3 text-slate-600 dark:text-slate-400 uppercase text-[10px] font-bold italic">{tx.paymentMethod || 'OUTROS'}</td>
                            <td className={`p-3 text-right font-mono font-bold ${tx.amount < 0 ? 'text-red-500' : tx.amount > 0 ? 'text-emerald-600 dark:text-emerald-400' : 'text-slate-400'}`}>
                                {activeMapping ? formatToBRL(tx.amount) : '-'}
                            </td>
                            <td className="p-3 text-center">
                                {!isIgnored && (
                                    <button onClick={() => onStartEdit(tx, idx)} className="p-1.5 text-slate-400 hover:text-brand-blue hover:bg-blue-50 rounded-lg transition-all opacity-0 group-hover:opacity-100">
                                        <PencilIcon className="w-3.5 h-3.5" />
                                    </button>
                                )}
                            </td>
                        </tr>
                    );
                })}
            </tbody>
        </table>
    );
};
